INSERT INTO t_p56980273_numismatic_database_.coins
    (name, year, country, metal, weight_g, diameter_mm, mintage, rarity, condition, base_price, current_price, description, ruler, dynasty, mint, tags)
VALUES
    ('50 копеек 1921 года', 1921, 'РСФСР', 'Серебро', 9.998, 26.67, 200000, 'редкая', 'VF', 28000.00, 34000.00, 'Серебряная полтина первого года советской чеканки. На аверсе — герб РСФСР, на реверсе — кузнец с молотом на фоне восходящего солнца. Редкая монета переходного периода.', NULL, NULL, 'Петроградский монетный двор', ARRAY['РСФСР', 'Серебро', 'XX век', 'Советские', '1921']),
    ('1 рубль 1921 года', 1921, 'РСФСР', 'Серебро', 19.996, 33.65, 100000, 'очень редкая', 'VF', 95000.00, 120000.00, 'Первый советский серебряный рубль. Крайне редкий, выпущен малым тиражом. На аверсе — герб РСФСР, на реверсе — номинал в венке из колосьев. Высоко ценится среди коллекционеров.', NULL, NULL, 'Петроградский монетный двор', ARRAY['РСФСР', 'Серебро', 'XX век', 'Советские', '1921', 'Редкий']),
    ('10 копеек 1923 года', 1923, 'РСФСР', 'Серебро', 1.800, 17.27, 1000000, 'обычная', 'XF', 1500.00, 2200.00, 'Серебряная монета периода НЭПа. Одна из первых советских разменных монет нового образца.', NULL, NULL, 'Петроградский монетный двор', ARRAY['РСФСР', 'Серебро', 'НЭП', '1923']),
    ('20 копеек 1923 года', 1923, 'РСФСР', 'Серебро', 3.600, 21.80, 1000000, 'обычная', 'XF', 2800.00, 3900.00, 'Серебряная монета эпохи НЭПа. На аверсе — герб РСФСР, на реверсе — номинал в венке.', NULL, NULL, 'Петроградский монетный двор', ARRAY['РСФСР', 'Серебро', 'НЭП', '1923']),
    ('50 копеек 1924 года', 1924, 'СССР', 'Серебро', 9.998, 26.67, 400000, 'редкая', 'XF', 18000.00, 23000.00, 'Полтинник первого года чеканки СССР. На аверсе — кузнец с молотом, на реверсе — герб СССР. Первая монета с надписью «СССР».', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Серебро', '1924', 'Полтинник']),
    ('1 рубль 1924 года', 1924, 'СССР', 'Серебро', 19.996, 33.65, 3000000, 'редкая', 'XF', 35000.00, 44000.00, 'Первый советский рубль с надписью «СССР». Крупная серебряная монета высокого художественного качества. На аверсе — рабочий и крестьянин с серпом и молотом.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Серебро', '1924', 'Рубль']),
    ('10 копеек 1925 года', 1925, 'СССР', 'Серебро', 1.800, 17.27, 2000000, 'обычная', 'XF', 800.00, 1200.00, 'Серебряная разменная монета периода НЭПа. Стандартный выпуск Ленинградского монетного двора.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Серебро', 'НЭП', '1925']),
    ('50 копеек 1926 года', 1926, 'СССР', 'Серебро', 9.998, 26.67, 350000, 'редкая', 'VF', 22000.00, 28000.00, 'Серебряный полтинник позднего периода НЭПа. Выпускался ограниченным тиражом. На аверсе — кузнец с молотом на наковальне.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Серебро', 'НЭП', '1926']),
    ('20 копеек 1927 года', 1927, 'СССР', 'Серебро', 3.600, 21.80, 1500000, 'обычная', 'XF', 1800.00, 2600.00, 'Серебряная монета позднего НЭПа. Последние годы серебряного денежного обращения в СССР.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Серебро', 'НЭП', '1927']),
    ('10 копеек 1931 года', 1931, 'СССР', 'Никель', 1.800, 17.27, 5000000, 'обычная', 'XF', 400.00, 650.00, 'Первые никелевые монеты СССР — переход от серебра к недрагоценным металлам. Начало новой денежной эпохи советского государства.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Никель', '1931', 'Индустриализация']),
    ('20 копеек 1931 года', 1931, 'СССР', 'Никель', 3.600, 21.80, 5000000, 'обычная', 'XF', 600.00, 950.00, 'Никелевая монета первого года перехода на недрагоценные металлы. Историческая монета советской денежной реформы 1931 года.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Никель', '1931', 'Индустриализация']),
    ('3 копейки 1935 года', 1935, 'СССР', 'Бронза', 3.000, 22.00, 10000000, 'обычная', 'XF', 350.00, 580.00, 'Бронзовая монета сталинской эпохи. Новый герб СССР с семью лентами на реверсе — изменение в связи с принятием Конституции СССР.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Бронза', '1935', 'Сталинская эпоха']),
    ('5 копеек 1935 года', 1935, 'СССР', 'Бронза', 5.000, 25.00, 10000000, 'обычная', 'XF', 450.00, 720.00, 'Бронзовая монета нового образца 1935 года. Смена дизайна в связи с конституционной реформой. Трактор на реверсе — символ коллективизации.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Бронза', '1935', 'Сталинская эпоха']),
    ('20 копеек 1936 года', 1936, 'СССР', 'Никель', 3.600, 21.80, 8000000, 'обычная', 'XF', 700.00, 1100.00, 'Никелевая монета переходного дизайна. Выпущена в год принятия «сталинской конституции».', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Никель', '1936', 'Сталинская эпоха']),
    ('1 рубль 1938 года', 1938, 'СССР', 'Никель', 8.000, 27.00, 5000000, 'редкая', 'VF', 45000.00, 62000.00, 'Никелевый рубль сталинской эпохи с изображением Ленина. Редкая монета — большинство экземпляров было переплавлено в годы Второй мировой войны.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Никель', '1938', 'Сталинская эпоха', 'Ленин']),
    ('2 копейки 1941 года', 1941, 'СССР', 'Бронза', 2.000, 18.00, 3000000, 'редкая', 'VF', 2500.00, 3800.00, 'Бронзовая монета военного года. Монеты 1941 года встречаются редко — производство резко сократилось в связи с началом Великой Отечественной войны.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Бронза', '1941', 'Военные', 'ВОВ']),
    ('1 копейка 1943 года', 1943, 'СССР', 'Бронза', 1.000, 15.00, 1000000, 'очень редкая', 'VF', 8000.00, 12000.00, 'Монета военного времени. Крайне редкая — в период Великой Отечественной войны производство монет было минимальным. Ленинградский монетный двор эвакуирован в Краснокамск.', NULL, NULL, 'Краснокамский монетный двор', ARRAY['СССР', 'Бронза', '1943', 'Военные', 'ВОВ', 'Редкий']),
    ('1 рубль 1945 года', 1945, 'СССР', 'Медно-никель', 8.000, 27.00, 2000000, 'редкая', 'XF', 38000.00, 49000.00, 'Рубль года Победы. Монета выпущена в год окончания Великой Отечественной войны. Исторически значимый нумизматический объект.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Медно-никель', '1945', 'Победа', 'ВОВ']),
    ('5 копеек 1946 года', 1946, 'СССР', 'Бронза', 5.000, 25.00, 8000000, 'обычная', 'XF', 500.00, 780.00, 'Бронзовая монета послевоенного восстановления. Новый тип герба СССР с 16 лентами — по числу союзных республик после 1946 года.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Бронза', '1946', 'Послевоенные']),
    ('20 копеек 1946 года', 1946, 'СССР', 'Медно-никель', 3.600, 21.80, 7000000, 'обычная', 'XF', 900.00, 1400.00, 'Монета послевоенного периода с новым гербом СССР с 16 лентами. Начало послевоенного восстановления денежного обращения.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Медно-никель', '1946', 'Послевоенные']),
    ('1 рубль 1947 года', 1947, 'СССР', 'Медно-никель', 8.000, 27.00, 1500000, 'очень редкая', 'XF', 120000.00, 155000.00, 'Крайне редкий рубль — выпущен пробным тиражом накануне денежной реформы 1947 года. Один из наиболее ценных советских рублей. Большинство было уничтожено.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Медно-никель', '1947', 'Редкий', 'Реформа']),
    ('10 копеек 1949 года', 1949, 'СССР', 'Медно-никель', 1.800, 17.27, 6000000, 'обычная', 'XF', 600.00, 900.00, 'Монета послереформенного периода. Выпущена после денежной реформы 1947 года, установившей новый курс советского рубля.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Медно-никель', '1949', 'Послереформенные']),
    ('2 копейки 1951 года', 1951, 'СССР', 'Бронза', 2.000, 18.00, 9000000, 'обычная', 'MS', 300.00, 480.00, 'Бронзовая монета позднесталинского периода. Стандартный чекан высокого качества Ленинградского монетного двора.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Бронза', '1951', 'Сталинская эпоха']),
    ('1 рубль 1953 года', 1953, 'СССР', 'Медно-никель', 8.000, 27.00, 3000000, 'редкая', 'XF', 32000.00, 41000.00, 'Рубль года смерти Сталина. Монета выпущена в переломный год советской истории. Представляет значительный исторический интерес.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Медно-никель', '1953', 'Сталинская эпоха']),
    ('5 копеек 1955 года', 1955, 'СССР', 'Бронза', 5.000, 25.00, 10000000, 'обычная', 'MS', 280.00, 420.00, 'Бронзовая монета периода «оттепели». Начало хрущёвского периода советской истории. Стандартный чекан хорошего качества.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Бронза', '1955', 'Оттепель']),
    ('1 рубль 1956 года', 1956, 'СССР', 'Медно-никель', 8.000, 27.00, 4000000, 'редкая', 'XF', 28000.00, 36000.00, 'Рубль года XX съезда КПСС и начала «оттепели». Последний год чеканки рублей старого советского образца перед реформой 1961 года.', NULL, NULL, 'Ленинградский монетный двор', ARRAY['СССР', 'Медно-никель', '1956', 'Оттепель', 'Хрущёв']);
